import{_ as t,o as s,c as a,a2 as o}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Installing Rust","description":"Install the Rust toolchain with rustup and configure your editor for a productive development workflow with rust-analyzer.","frontmatter":{"title":"Installing Rust","description":"Install the Rust toolchain with rustup and configure your editor for a productive development workflow with rust-analyzer."},"headers":[],"relativePath":"learn/project/01-hello-rust-cli/02-installing-rust.md","filePath":"learn/project/01-hello-rust-cli/02-installing-rust.md"}'),n={name:"learn/project/01-hello-rust-cli/02-installing-rust.md"};function l(i,e,r,c,p,u){return s(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="installing-rust" tabindex="-1">Installing Rust <a class="header-anchor" href="#installing-rust" aria-label="Permalink to &quot;Installing Rust&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to install Rust on macOS, Linux, and Windows using rustup</li><li>How to verify your installation and understand stable, beta, and nightly channels</li><li>How to set up rust-analyzer in your editor for autocompletion and inline error reporting</li></ul></blockquote><p>Before you write a single line of Rust, you need the toolchain on your machine. The good news: Rust has one of the smoothest installation experiences in the compiled-language world. A single command gets you the compiler, the build tool, the package manager, and the documentation — all managed by a version manager called <strong>rustup</strong>.</p><h2 id="installing-with-rustup" tabindex="-1">Installing with rustup <a class="header-anchor" href="#installing-with-rustup" aria-label="Permalink to &quot;Installing with rustup&quot;">​</a></h2><p><code>rustup</code> is the official Rust toolchain installer and version manager. Think of it as the equivalent of <code>pyenv</code> for Python — it lets you install multiple Rust versions, switch between them, and keep everything up to date.</p><h3 id="macos-and-linux" tabindex="-1">macOS and Linux <a class="header-anchor" href="#macos-and-linux" aria-label="Permalink to &quot;macOS and Linux&quot;">​</a></h3><p>Open your terminal and run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> --proto</span><span style="color:#A6E3A1;"> &#39;=https&#39;</span><span style="color:#A6E3A1;"> --tlsv1.2</span><span style="color:#A6E3A1;"> -sSf</span><span style="color:#A6E3A1;"> https://sh.rustup.rs</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> sh</span></span></code></pre></div><p>The installer walks you through a few options. Choose the default installation (option 1) unless you have a specific reason to customize. When it finishes, it adds Rust&#39;s binaries to your shell&#39;s PATH. You may need to restart your terminal or run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;font-style:italic;">source</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$HOME</span><span style="color:#A6E3A1;">/.cargo/env&quot;</span></span></code></pre></div><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><p>On Windows, download and run <code>rustup-init.exe</code> from <a href="https://rustup.rs" target="_blank" rel="noreferrer">https://rustup.rs</a>. The installer handles everything, including setting up the MSVC build tools that Rust needs on Windows.</p><p>If you prefer the Windows Subsystem for Linux (WSL), use the macOS/Linux instructions above inside your WSL terminal.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you have used <code>pyenv</code> to manage Python versions, <code>rustup</code> fills the same role. The key difference: <code>rustup</code> is the <em>official</em> tool blessed by the Rust project, so there is no confusion about which installer to use. Unlike Python&#39;s ecosystem — where you might choose between <code>pyenv</code>, <code>conda</code>, <code>asdf</code>, or system packages — Rust has one answer: <code>rustup</code>.</p></div><h2 id="verifying-your-installation" tabindex="-1">Verifying Your Installation <a class="header-anchor" href="#verifying-your-installation" aria-label="Permalink to &quot;Verifying Your Installation&quot;">​</a></h2><p>Once the installer finishes, verify that everything is working:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustc</span><span style="color:#A6E3A1;"> --version</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> --version</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> --version</span></span></code></pre></div><p>You should see output similar to:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>rustc 1.84.0 (9fc6b43 2025-01-07)</span></span>
<span class="line"><span>cargo 1.84.0 (fb7c438 2024-12-20)</span></span>
<span class="line"><span>rustup 1.27.1 (54dd3d0 2024-04-24)</span></span></code></pre></div><p>The exact version numbers will differ depending on when you install, but all three commands should succeed. Here is what each tool does:</p><ul><li><strong><code>rustc</code></strong> — the Rust compiler. You rarely call it directly (Cargo handles that), but it is the engine under the hood.</li><li><strong><code>cargo</code></strong> — the build tool and package manager. You use this constantly. It builds your code, runs tests, manages dependencies, and more.</li><li><strong><code>rustup</code></strong> — the toolchain manager. It installs and updates <code>rustc</code>, <code>cargo</code>, and other components.</li></ul><h2 id="understanding-toolchain-channels" tabindex="-1">Understanding Toolchain Channels <a class="header-anchor" href="#understanding-toolchain-channels" aria-label="Permalink to &quot;Understanding Toolchain Channels&quot;">​</a></h2><p>Rust ships on three release channels:</p><table tabindex="0"><thead><tr><th>Channel</th><th>Release Cadence</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>stable</strong></td><td>Every 6 weeks</td><td>Production code — this is your default</td></tr><tr><td><strong>beta</strong></td><td>Every 6 weeks (previews the next stable)</td><td>Testing upcoming features</td></tr><tr><td><strong>nightly</strong></td><td>Every night</td><td>Experimental features, bleeding-edge crates</td></tr></tbody></table><p>As a beginner, you should stay on <strong>stable</strong>. Every example in this book works on stable Rust. The only reason to install nightly is if a specific crate requires it (we will note when that happens — it is rare).</p><p>To update your toolchain to the latest stable release:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> update</span><span style="color:#A6E3A1;"> stable</span></span></code></pre></div><p>To check which toolchain is currently active:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> show</span></span></code></pre></div><h2 id="installing-helpful-components" tabindex="-1">Installing Helpful Components <a class="header-anchor" href="#installing-helpful-components" aria-label="Permalink to &quot;Installing Helpful Components&quot;">​</a></h2><p>The Rust toolchain comes with several optional components that make development smoother. Install these now:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> component</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> clippy</span><span style="color:#A6E3A1;"> rustfmt</span></span></code></pre></div><ul><li><strong><code>clippy</code></strong> — a linter that catches common mistakes and suggests idiomatic improvements. Think of it as <code>pylint</code> or <code>flake8</code> for Rust.</li><li><strong><code>rustfmt</code></strong> — an automatic code formatter. It is the equivalent of <code>black</code> for Python. Run it with <code>cargo fmt</code> and never argue about code style again.</li></ul><p>You can try them immediately:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Format all code in your project</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> fmt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run the linter</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> clippy</span></span></code></pre></div><p>(These won&#39;t do much until you have a project, but they will be ready when you do.)</p><h2 id="setting-up-your-editor" tabindex="-1">Setting Up Your Editor <a class="header-anchor" href="#setting-up-your-editor" aria-label="Permalink to &quot;Setting Up Your Editor&quot;">​</a></h2><p>Rust has excellent editor support through <strong>rust-analyzer</strong>, the official language server. It gives you:</p><ul><li>Real-time error highlighting as you type</li><li>Autocompletion with type information</li><li>Inline type hints for variables where Rust infers the type</li><li>Go-to-definition, find-all-references, and rename refactoring</li><li>Code actions to automatically apply compiler suggestions</li></ul><h3 id="vs-code" tabindex="-1">VS Code <a class="header-anchor" href="#vs-code" aria-label="Permalink to &quot;VS Code&quot;">​</a></h3><p>Install the <strong>rust-analyzer</strong> extension from the VS Code marketplace. Search for &quot;rust-analyzer&quot; (the publisher is &quot;rust-lang&quot;). That is it — no extra configuration needed. When you open a Rust project, rust-analyzer automatically detects the <code>Cargo.toml</code> and starts analyzing your code.</p><p>Recommended additional extensions:</p><ul><li><strong>Even Better TOML</strong> — syntax highlighting for <code>Cargo.toml</code></li><li><strong>Error Lens</strong> — shows error messages inline next to the problematic line</li><li><strong>CodeLLDB</strong> — debugger support for Rust</li></ul><h3 id="zed" tabindex="-1">Zed <a class="header-anchor" href="#zed" aria-label="Permalink to &quot;Zed&quot;">​</a></h3><p>Zed has built-in Rust support powered by rust-analyzer. Open a Rust project and it works out of the box.</p><h3 id="neovim" tabindex="-1">Neovim <a class="header-anchor" href="#neovim" aria-label="Permalink to &quot;Neovim&quot;">​</a></h3><p>If you use Neovim with the built-in LSP client, add rust-analyzer to your LSP configuration. If you use a plugin manager like <code>lazy.nvim</code>, the <code>mason.nvim</code> plugin can install rust-analyzer for you automatically.</p><h3 id="jetbrains-rustrover-or-intellij-rust-plugin" tabindex="-1">JetBrains (RustRover or IntelliJ + Rust Plugin) <a class="header-anchor" href="#jetbrains-rustrover-or-intellij-rust-plugin" aria-label="Permalink to &quot;JetBrains (RustRover or IntelliJ + Rust Plugin)&quot;">​</a></h3><p>JetBrains offers <strong>RustRover</strong>, a dedicated Rust IDE, or you can use the Rust plugin with IntelliJ IDEA. Both provide excellent Rust support with their own analysis engine.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you currently use VS Code with Pylance for Python, switching to rust-analyzer for Rust feels very similar. The big upgrade: Rust&#39;s type system is fully static, so rust-analyzer can give you <em>exact</em> type information everywhere — no guessing, no <code># type: ignore</code>. Autocompletion is precise because every type is known at compile time.</p></div><h2 id="your-first-compile-test" tabindex="-1">Your First Compile Test <a class="header-anchor" href="#your-first-compile-test" aria-label="Permalink to &quot;Your First Compile Test&quot;">​</a></h2><p>Let&#39;s verify that everything works end-to-end. Create a temporary file and compile it:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &#39;fn main() { println!(&quot;Rust is ready!&quot;); }&#39;</span><span style="color:#94E2D5;"> &gt;</span><span style="color:#A6E3A1;"> /tmp/test_rust.rs</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustc</span><span style="color:#A6E3A1;"> /tmp/test_rust.rs</span><span style="color:#A6E3A1;"> -o</span><span style="color:#A6E3A1;"> /tmp/test_rust</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">/tmp/test_rust</span></span></code></pre></div><p>You should see:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Rust is ready!</span></span></code></pre></div><p>This compiles a Rust source file directly with <code>rustc</code>. In practice, you almost never do this — you use <code>cargo</code> instead, which handles compilation, linking, and dependency management for you. But it is useful to know that <code>rustc</code> is there and that your toolchain works.</p><p>Clean up:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rm</span><span style="color:#A6E3A1;"> /tmp/test_rust.rs</span><span style="color:#A6E3A1;"> /tmp/test_rust</span></span></code></pre></div><h2 id="keeping-rust-up-to-date" tabindex="-1">Keeping Rust Up to Date <a class="header-anchor" href="#keeping-rust-up-to-date" aria-label="Permalink to &quot;Keeping Rust Up to Date&quot;">​</a></h2><p>Rust releases a new stable version every six weeks. To update:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> update</span></span></code></pre></div><p>This updates all installed channels (stable, beta, nightly) to their latest versions. Get in the habit of running this periodically — Rust is backward-compatible, so updating stable never breaks your existing code.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Install Rust with <code>rustup</code>, the official toolchain manager — one command gives you the compiler (<code>rustc</code>), build tool (<code>cargo</code>), and version manager (<code>rustup</code>).</li><li>Stay on the <strong>stable</strong> channel for all the code in this book. Update regularly with <code>rustup update</code>.</li><li>Install <code>clippy</code> and <code>rustfmt</code> immediately — they catch bugs and format your code automatically, just like <code>flake8</code> and <code>black</code> do in Python.</li><li>Set up <strong>rust-analyzer</strong> in your editor for real-time error checking, autocompletion, and inline type hints — it is the single biggest productivity boost for Rust development.</li><li>Verify your installation with <code>rustc --version</code>, <code>cargo --version</code>, and a quick compile test before moving on.</li></ul>`,64)])])}const y=t(n,[["render",l]]);export{h as __pageData,y as default};
